_shaderData.warp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;
  // sample previous uFrame
ret = texture( sampler_main, vUv ).xyz;
float blur =sin(audioLow*90)*vRadius;
ret=0.125*(
GetPixel(vec2(vUv.x-0.01*blur,vUv.y-0.01*blur)) +
GetPixel(vec2(vUv.x+0.01*blur,vUv.y+0.01*blur)) +
GetPixel(vec2(vUv.x-0.01*blur,vUv.y+0.01*blur)) +
GetPixel(vec2(vUv.x+0.01*blur,vUv.y-0.01*blur)) +
GetPixel(vec2(vUv.x,vUv.y-0.01*blur)) +
GetPixel(vec2(vUv.x,vUv.y+0.01*blur)) +
GetPixel(vec2(vUv.x-0.01*blur,vUv.y)) +
GetPixel(vec2(vUv.x+0.01*blur,vUv.y)));
//add a 'audioLow overbright' effect:
ret-=-(lum(ret)<sin(uTime*90))*ret*blur+(lum(ret)>sin(-uTime*90))*ret*blur;

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

uv1=multiply(vUv-0.5, mat2(cos(q5),-sin(q5),sin(q5),cos(q5)));
float z=1/(uv1.y);
vec2 uv2 = vec2 (uv1.x*z,z)*.25;
vec2 water = texture(sampler_noise_mq,uv2/2+vec2(0,uTime/2))/z;

uvw= uv1*vec2 (1,.5)+0.5+water*0.2*(z>0);
uvw = fract(uvw);

ret = (GetPixel(vUv) + GetBlur2(vUv) * (0.75+abs(uv1.y)*3));
ret += clamp01(1-2*lum(ret)) * pow(GetBlur1(uvw),2)*clamp01(.4/z)*64*clamp01(1-vRadius);
ret *= 1.1;

vUv=1-vUv;
uv1=(vUv+sin(q5/5))*uAspect.xy;
uv3=(vUv-tan(q5/3))*uAspect.xy;
uv5=(vUv-sin(q5))*uAspect.xy;
ret += 0.005/length(uv1-0.4) + 0.005/length(uv3-0.5) + 0.005/length(uv5-0.4);
ret *=1.5;
ret -=0.07;
//MilkDrop3 Color Mode:
ret /= vec3(1.1,1.9,1.0);

  fragColor = ret;
}
